import './PresetPeriods.scss';

import { Button } from ':components/Button';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';

import type { PresetPeriod } from '../../Calendar.types';

export interface PresetPeriodsProps {
	periods: PresetPeriod[];
	onSelect: (range: [string, string]) => void;
	className?: string;
	dataTestId?: string;
}

const formatDate = (date: Date | string) => {
	if (!date) {
		return '';
	}
	if (typeof date === 'string') {
		// Если вдруг уже формат ДД.ММ.ГГГГ, не трогаем
		if (/^(?:\d{2}\.){2}\d{4}$/.test(date)) {
			return date;
		}
		// Иначе парсим как дату
		date = new Date(date);
	}
	const day = String((date as Date).getDate()).padStart(2, '0');
	const month = String((date as Date).getMonth() + 1).padStart(2, '0');
	const year = (date as Date).getFullYear();
	return `${day}.${month}.${year}`;
};

export const PresetPeriods: FC<PresetPeriodsProps & { selectedRange?: [string, string] }> = ({
	periods,
	onSelect,
	className,
	dataTestId = 'PresetPeriods',
	selectedRange,
}) => (
	<div className={classNames('dsb_preset-periods', className)} data-testid={dataTestId}>
		{periods.map((period, index) => (
			<div key={period.label} style={{ marginBottom: 0, width: 'calc(50% - 12px)' }}>
				<Button
					fullWidth={true}
					variant="outlined"
					size="small"
					className="dsb_preset-periods-item"
					data-testid={`${dataTestId}-item-${index}`}
					onClick={() => onSelect(period.range)}
				>
					<div>
						<Typography variant="body2">{period.label}</Typography>

						<Typography variant="body3" className="dsb_preset-periods-date">
							{formatDate(period.range[0])}–{formatDate(period.range[1])}
						</Typography>
					</div>
				</Button>
			</div>
		))}
	</div>
);
